// RFC 9457 Problem Details body shape (type, title, status, detail) so agents
// can parse a structured error instead of scraping an HTML page. Served as
// `application/json` rather than the canonical `application/problem+json`:
// problem+json is sparsely supported and many agent toolchains substring-match
// the content-type for "application/json", so they treat problem+json as
// non-JSON. Same body, the universally-recognized media type.

export type Problem = {
	type: string;
	title: string;
	status: number;
	detail?: string;
	instance?: string;
};

export function problemResponse(
	problem: Omit<Problem, "type"> & { type?: string },
	extraHeaders: Record<string, string> = {},
): Response {
	const body: Problem = {
		// Default to the RFC's "no further info" URN when no specific type is given.
		type: problem.type ?? "about:blank",
		title: problem.title,
		status: problem.status,
		...(problem.detail ? { detail: problem.detail } : {}),
		...(problem.instance ? { instance: problem.instance } : {}),
	};

	return new Response(JSON.stringify(body), {
		status: problem.status,
		headers: {
			"Content-Type": "application/json; charset=utf-8",
			...extraHeaders,
		},
	});
}

// RFC 8594 deprecation signalling. Nothing is deprecated today; this is the
// mechanism the OpenAPI deprecation policy (info.description) promises, ready
// to spread into any endpoint's response headers when an endpoint is actually
// retired. `deprecation` is the date the endpoint became deprecated and
// `sunset` is the date it stops working (both serialized as IMF-fixdate, the
// HTTP-date format both RFC 8594 headers require). `migrationDocsUrl` adds the
// RFC 8288 `Link: rel="deprecation"` pointer to the migration notes.
export function deprecationHeaders(opts: {
	deprecation: Date;
	sunset?: Date;
	migrationDocsUrl?: string;
}): Record<string, string> {
	const headers: Record<string, string> = {
		Deprecation: opts.deprecation.toUTCString(),
	};
	if (opts.sunset) headers.Sunset = opts.sunset.toUTCString();
	if (opts.migrationDocsUrl) {
		headers.Link = `<${opts.migrationDocsUrl}>; rel="deprecation"; type="text/html"`;
	}
	return headers;
}
